{
  "version": "arkpilot-a2ui/v2",
  "kind": "semantic-ui-protocol",
  "appName": "今天吃什么",
  "targetDevice": {
    "widthVp": 1272,
    "heightVp": 2756,
    "contentMaxWidthVp": 420
  },
  "surfaces": [
    {
      "id": "home-page",
      "surfaceId": "home",
      "pageId": "home",
      "name": "今日决策首页",
      "route": "pages/Home",
      "tabId": "tab-home",
      "semanticTargets": [
        {
          "id": "home-title",
          "role": "assertion",
          "binding": "/pageTitle"
        },
        {
          "id": "home-quick-wheel-button",
          "role": "action",
          "event": "open-wheel"
        },
        {
          "id": "home-filter-button",
          "role": "action",
          "event": "open-filter"
        },
        {
          "id": "home-recommend-list",
          "role": "list",
          "binding": "/recommendations",
          "itemIdPattern": "home-dish-{id}",
          "emptyStateId": "home-empty-recommendations"
        },
        {
          "id": "home-today-record-status",
          "role": "assertion",
          "binding": "/todayRecord/status"
        },
        {
          "id": "home-add-record-button",
          "role": "action",
          "event": "open-add-record"
        }
      ]
    },
    {
      "id": "wheel-page",
      "surfaceId": "wheel",
      "pageId": "wheel",
      "name": "随机转盘",
      "route": "pages/Wheel",
      "semanticTargets": [
        {
          "id": "wheel-back-button",
          "role": "action",
          "event": "navigate-back"
        },
        {
          "id": "wheel-title",
          "role": "assertion",
          "binding": "/pageTitle"
        },
        {
          "id": "wheel-canvas",
          "role": "assertion",
          "binding": "/wheel/candidates"
        },
        {
          "id": "wheel-spin-button",
          "role": "action",
          "event": "spin-wheel"
        },
        {
          "id": "wheel-result-name",
          "role": "assertion",
          "binding": "/wheel/result/name"
        },
        {
          "id": "wheel-result-accept-button",
          "role": "action",
          "event": "accept-result"
        },
        {
          "id": "wheel-result-reshuffle-button",
          "role": "action",
          "event": "reshuffle"
        },
        {
          "id": "wheel-share-button",
          "role": "action",
          "event": "open-share-card"
        }
      ]
    },
    {
      "id": "ingredients-page",
      "surfaceId": "ingredients",
      "pageId": "ingredients",
      "name": "冰箱食材",
      "route": "pages/Ingredients",
      "tabId": "tab-ingredients",
      "semanticTargets": [
        {
          "id": "ingredients-title",
          "role": "assertion",
          "binding": "/pageTitle"
        },
        {
          "id": "ingredients-input",
          "role": "input",
          "event": "add-ingredient"
        },
        {
          "id": "ingredients-add-button",
          "role": "action",
          "event": "add-ingredient"
        },
        {
          "id": "ingredients-list",
          "role": "list",
          "binding": "/ingredients",
          "itemIdPattern": "ingredient-{id}",
          "emptyStateId": "ingredients-empty-state"
        },
        {
          "id": "ingredient-delete-button",
          "role": "action",
          "event": "delete-ingredient"
        },
        {
          "id": "ingredients-recommend-button",
          "role": "action",
          "event": "show-ingredient-recommendations"
        },
        {
          "id": "ingredients-dish-list",
          "role": "list",
          "binding": "/ingredientRecommendations",
          "itemIdPattern": "ingredients-dish-{id}",
          "emptyStateId": "ingredients-empty-recommendations"
        }
      ]
    },
    {
      "id": "filter-page",
      "surfaceId": "filter",
      "pageId": "filter",
      "name": "筛选条件",
      "route": "pages/Filter",
      "semanticTargets": [
        {
          "id": "filter-back-button",
          "role": "action",
          "event": "navigate-back"
        },
        {
          "id": "filter-mood-group",
          "role": "input",
          "binding": "/filter/mood"
        },
        {
          "id": "filter-time-group",
          "role": "input",
          "binding": "/filter/time"
        },
        {
          "id": "filter-meal-group",
          "role": "input",
          "binding": "/filter/meal"
        },
        {
          "id": "filter-apply-button",
          "role": "action",
          "event": "apply-filter"
        },
        {
          "id": "filter-reset-button",
          "role": "action",
          "event": "reset-filter"
        }
      ]
    },
    {
      "id": "records-page",
      "surfaceId": "records",
      "pageId": "records",
      "name": "饮食打卡",
      "route": "pages/Records",
      "tabId": "tab-records",
      "semanticTargets": [
        {
          "id": "records-title",
          "role": "assertion",
          "binding": "/pageTitle"
        },
        {
          "id": "records-calendar",
          "role": "assertion",
          "binding": "/records/calendar"
        },
        {
          "id": "records-add-button",
          "role": "action",
          "event": "open-add-record"
        },
        {
          "id": "records-list",
          "role": "list",
          "binding": "/records",
          "itemIdPattern": "record-{id}",
          "emptyStateId": "records-empty-state"
        },
        {
          "id": "record-share-button",
          "role": "action",
          "event": "open-share-card"
        }
      ]
    },
    {
      "id": "record-form-sheet",
      "surfaceId": "record-form",
      "pageId": "record-form",
      "name": "打卡表单",
      "route": "pages/RecordForm",
      "semanticTargets": [
        {
          "id": "record-form-date-picker",
          "role": "input",
          "binding": "/record/date"
        },
        {
          "id": "record-form-meal-group",
          "role": "input",
          "binding": "/record/meal"
        },
        {
          "id": "record-form-dish-input",
          "role": "input",
          "binding": "/record/dishName"
        },
        {
          "id": "record-form-rating",
          "role": "input",
          "binding": "/record/rating"
        },
        {
          "id": "record-form-note-input",
          "role": "input",
          "binding": "/record/note"
        },
        {
          "id": "record-form-save-button",
          "role": "action",
          "event": "save-record"
        },
        {
          "id": "record-form-cancel-button",
          "role": "action",
          "event": "cancel-record"
        }
      ]
    },
    {
      "id": "share-card-page",
